'use client';

import { useTheme } from 'next-themes';
import { useEffect, useState } from 'react';

export default function ThemeSwitch() {
  const { theme, setTheme, systemTheme } = useTheme();
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  if (!mounted) return null;

  const current = theme === 'system' ? systemTheme : theme;
  return (
    <button
      onClick={() => setTheme(current === 'dark' ? 'light' : 'dark')}
      className="fixed bottom-4 right-4 z-50 p-2 rounded-full bg-gray-200 dark:bg-gray-700 text-gray-800 dark:text-gray-200 shadow-lg hover:scale-110 transition-all"
    >
      {current === 'dark' ? '🌞' : '🌙'}
    </button>
  );
}

"use client";

import React from "react";
import { Clock, Edit2, Trash2 } from "lucide-react";
import type { AvailableRecipe } from "@/features/Recipes/recetasData";

interface AvailableRecipeCardProps {
    recipe: AvailableRecipe;
    onClick: (recipe: AvailableRecipe) => void;
    onEdit?: (recipe: AvailableRecipe) => void;
    onDelete?: (recipe: AvailableRecipe) => void;
}

export default function AvailableRecipeCard({ recipe, onClick, onEdit, onDelete }: AvailableRecipeCardProps) {
    return (
        <div
            onClick={() => onClick(recipe)}
            className="cursor-pointer bg-white dark:bg-background-dark border border-gray-200 dark:border-white/10 rounded-xl overflow-hidden text-left hover:shadow-md hover:border-emerald-500 dark:hover:border-emerald-500 hover:-translate-y-0.5 transition-all duration-200 flex flex-col group relative"
        >
            {/* Image placeholder or Real image */}
            <div className="relative w-full h-36 bg-gray-100 dark:bg-zinc-800 flex items-center justify-center shrink-0 overflow-hidden">
                {recipe.imageUrl ? (
                    <img
                        src={recipe.imageUrl}
                        alt={recipe.name}
                        className="w-full h-full object-cover"
                    />
                ) : (
                    <span className="text-gray-300 dark:text-white/30 text-3xl">🍽️</span>
                )}

                {/* Badge */}
                <span className="absolute top-2 left-2 bg-emerald-500 text-white text-[9px] font-bold px-2 py-0.5 rounded-md tracking-wide z-10">
                    {recipe.ingredientsBadge}
                </span>

                {/* Actions (visible on hover) */}
                <div className="absolute top-2 right-2 flex items-center gap-1 opacity-100 sm:opacity-0 sm:group-hover:opacity-100 transition-opacity z-10">
                    {onEdit && (
                        <button
                            onClick={(e) => { e.stopPropagation(); onEdit(recipe); }}
                            className="p-1.5 bg-white/90 dark:bg-black/50 backdrop-blur-sm rounded-md text-gray-700 dark:text-gray-300 hover:text-emerald-600 dark:hover:text-emerald-400 transition-colors shadow-sm"
                            title="Editar"
                        >
                            <Edit2 size={12} />
                        </button>
                    )}
                    {onDelete && (
                        <button
                            onClick={(e) => { e.stopPropagation(); onDelete(recipe); }}
                            className="p-1.5 bg-white/90 dark:bg-black/50 backdrop-blur-sm rounded-md text-gray-700 dark:text-gray-300 hover:text-red-500 dark:hover:text-red-400 transition-colors shadow-sm"
                            title="Eliminar"
                        >
                            <Trash2 size={12} />
                        </button>
                    )}
                </div>
            </div>

            <div className="p-3 flex flex-col gap-1 bg-white dark:bg-background-dark group-hover:bg-emerald-50/50 dark:group-hover:bg-white/5 transition-colors">
                <h3 className="text-sm font-bold text-gray-900 dark:text-white leading-tight">{recipe.name}</h3>
                <p className="text-[11px] text-gray-400 dark:text-gray-500 leading-relaxed line-clamp-2">
                    {recipe.description}
                </p>
            </div>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { X, Clock, PenTool, Plus, Trash2, Search, Info } from "lucide-react";
import type { AvailableRecipe } from "@/features/Recipes/recetasData";
import { catalogService, type Ingredient } from "@/services/catalog.service";

interface RecipeModalProps {
    initialData?: AvailableRecipe;
    onSave: (recipe: AvailableRecipe) => Promise<void> | void;
    onClose: () => void;
}

export default function RecipeModal({
    initialData,
    onSave,
    onClose,
}: RecipeModalProps) {
    const isEditing = !!initialData;
    const [name, setName] = useState(initialData?.name || "");
    const [description, setDescription] = useState(initialData?.description || "");
    const [instructions, setInstructions] = useState(initialData?.instructions || "");
    const [servings, setServings] = useState(initialData?.servings || "1-2");

    // Ingredients state
    const [selectedIngredients, setSelectedIngredients] = useState<any[]>(initialData?.ingredients || []);
    const [catalogIngredients, setCatalogIngredients] = useState<Ingredient[]>([]);
    const [searchQuery, setSearchQuery] = useState("");
    const [isSearching, setIsSearching] = useState(false);
    const [loadingIngredients, setLoadingIngredients] = useState(false);
    const [saving, setSaving] = useState(false);

    useEffect(() => {
        const fetchCatalog = async () => {
            setLoadingIngredients(true);
            const token = localStorage.getItem('token');
            if (!token) return;
            const res = await catalogService.getIngredients(token);
            if (res.ok && res.data) {
                setCatalogIngredients(res.data);
            }
            setLoadingIngredients(false);
        };
        fetchCatalog();
    }, []);

    const handleAddIngredient = (ing: Ingredient) => {
        if (selectedIngredients.some(si => si.ingredient_id === ing.id)) return;

        setSelectedIngredients([
            ...selectedIngredients,
            {
                ingredient_id: ing.id,
                name: ing.name,
                required_quantity: 1,
                unit: ing.unit_default || 'g'
            }
        ]);
        setSearchQuery("");
        setIsSearching(false);
    };

    const handleRemoveIngredient = (id: number) => {
        setSelectedIngredients(selectedIngredients.filter(si => si.ingredient_id !== id));
    };

    const handleUpdateQuantity = (id: number, qty: number) => {
        setSelectedIngredients(selectedIngredients.map(si =>
            si.ingredient_id === id ? { ...si, required_quantity: qty } : si
        ));
    };

    const handleSave = async () => {
        if (!name.trim() || !instructions.trim() || selectedIngredients.length === 0) return;

        setSaving(true);
        try {
            const recipeData: AvailableRecipe = {
                id: initialData?.id || Date.now().toString(),
                name,
                description,
                instructions,
                servings,
                timeMinutes: 30, // Default value since it's removed from UI
                ingredientsBadge: "LOCAL",
                imageUrl: initialData?.imageUrl || "/platillo-pre.png",
                ingredients: selectedIngredients
            };

            await onSave(recipeData);
            onClose();
        } catch (e) {
            console.error(e);
        } finally {
            setSaving(false);
        }
    };

    const filteredCatalog = catalogIngredients.filter(ing =>
        ing.name.toLowerCase().includes(searchQuery.toLowerCase()) &&
        !selectedIngredients.some(si => si.ingredient_id === ing.id)
    ).slice(0, 5);

    const isFormValid = name.trim() !== "" && instructions.trim() !== "" && selectedIngredients.length > 0;

    return (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-md flex items-center justify-center z-50 p-4 animate-in fade-in duration-200">
            <div className="bg-white dark:bg-zinc-900 border border-gray-200 dark:border-white/10 rounded-3xl shadow-2xl w-full max-w-2xl flex flex-col max-h-[90vh] overflow-hidden">
                {/* Header */}
                <div className="flex items-center justify-between px-6 py-5 border-b border-gray-100 dark:border-white/5 bg-gray-50/50 dark:bg-white/2">
                    <div>
                        <h3 className="text-xl font-black text-gray-900 dark:text-white">
                            {isEditing ? "Editar Receta" : "Nueva Receta"}
                        </h3>
                        <p className="text-xs text-gray-500 dark:text-zinc-500 font-medium">Completa los detalles para tu creación culinaria</p>
                    </div>
                    <button
                        onClick={onClose}
                        className="p-2 text-gray-400 dark:text-zinc-500 hover:text-gray-600 dark:hover:text-white hover:bg-gray-100 dark:hover:bg-white/5 rounded-full transition-all"
                    >
                        <X size={20} />
                    </button>
                </div>

                {/* Content */}
                <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
                    {/* Basic Info Grid */}
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                        {/* Name */}
                        <div className="md:col-span-2 space-y-2">
                            <label className="text-[10px] text-gray-400 dark:text-zinc-500 font-black uppercase tracking-widest px-1">Nombre</label>
                            <div className="relative group">
                                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 dark:text-zinc-600 group-focus-within:text-emerald-500 transition-colors">
                                    <PenTool size={16} />
                                </span>
                                <input
                                    type="text"
                                    value={name}
                                    onChange={(e) => setName(e.target.value)}
                                    className="w-full pl-11 pr-4 py-3 bg-gray-50 dark:bg-zinc-800/50 border border-gray-200 dark:border-zinc-800 rounded-2xl text-sm focus:ring-2 focus:ring-emerald-500/20 focus:border-emerald-500 outline-none transition-all dark:text-white"
                                    placeholder="Ej. Tacos de Pastor"
                                />
                            </div>
                        </div>

                        {/* Servings */}
                        <div className="space-y-2">
                            <label className="text-[10px] text-gray-400 dark:text-zinc-500 font-black uppercase tracking-widest px-1">Porciones</label>
                            <select
                                value={servings}
                                onChange={(e) => setServings(e.target.value)}
                                className="w-full px-4 py-3 bg-gray-50 dark:bg-zinc-800/50 border border-gray-200 dark:border-zinc-800 rounded-2xl text-sm focus:border-emerald-500 outline-none transition-all dark:text-white appearance-none cursor-pointer"
                            >
                                <option value="1-2" className="bg-white dark:bg-zinc-900">1-2 personas</option>
                                <option value="3-4" className="bg-white dark:bg-zinc-900">3-4 personas</option>
                                <option value="5-6" className="bg-white dark:bg-zinc-900">5-6 personas</option>
                                <option value="7-8" className="bg-white dark:bg-zinc-900">7-8 personas</option>
                            </select>
                        </div>
                    </div>

                    {/* Ingredients Section */}
                    <div className="space-y-3">
                        <label className="text-[10px] text-gray-400 dark:text-zinc-500 font-black uppercase tracking-widest px-1">Ingredientes</label>

                        {/* Selected List */}
                        <div className="space-y-2">
                            {selectedIngredients.map((ing) => (
                                <div key={ing.ingredient_id} className="flex items-center gap-3 bg-emerald-50/50 dark:bg-emerald-500/5 p-3 rounded-2xl border border-emerald-100 dark:border-emerald-500/20 animate-in zoom-in-95 duration-200">
                                    <div className="flex-1">
                                        <p className="text-sm font-bold text-gray-800 dark:text-white">{ing.name}</p>
                                    </div>
                                    <div className="flex items-center gap-2">
                                        <input
                                            type="number"
                                            value={ing.required_quantity}
                                            onChange={(e) => handleUpdateQuantity(ing.ingredient_id, Number(e.target.value))}
                                            className="w-16 px-2 py-1 bg-white dark:bg-zinc-800 border border-emerald-200 dark:border-zinc-700 rounded-lg text-xs font-bold text-center dark:text-white outline-none focus:border-emerald-500"
                                        />
                                        <span className="text-xs text-emerald-600 dark:text-emerald-400 font-bold w-8">{ing.unit}</span>
                                        <button
                                            onClick={() => handleRemoveIngredient(ing.ingredient_id)}
                                            className="p-1.5 text-red-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-500/10 rounded-lg transition-colors"
                                        >
                                            <Trash2 size={16} />
                                        </button>
                                    </div>
                                </div>
                            ))}
                        </div>

                        {/* Search Input */}
                        <div className="relative">
                            <Search size={16} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
                            <input
                                type="text"
                                value={searchQuery}
                                onFocus={() => setIsSearching(true)}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                className="w-full pl-11 pr-4 py-3 bg-gray-50 dark:bg-zinc-800/50 border border-gray-200 dark:border-zinc-800 rounded-2xl text-sm outline-none focus:border-emerald-500 transition-all dark:text-white"
                                placeholder="Busca un ingrediente en tu catálogo..."
                            />

                            {/* Dropdown Results */}
                            {isSearching && searchQuery.trim() !== "" && (
                                <div className="absolute top-full left-0 right-0 mt-2 bg-white dark:bg-zinc-800 border border-gray-100 dark:border-zinc-700 rounded-2xl shadow-2xl z-10 overflow-hidden animate-in slide-in-from-top-2 duration-200">
                                    {filteredCatalog.length > 0 ? (
                                        filteredCatalog.map(ing => (
                                            <button
                                                key={ing.id}
                                                onClick={() => handleAddIngredient(ing)}
                                                className="w-full flex items-center justify-between px-5 py-3 hover:bg-emerald-50 dark:hover:bg-emerald-500/10 text-left transition-colors border-b border-gray-50 dark:border-zinc-700/50 last:border-0"
                                            >
                                                <span className="text-sm font-medium text-gray-700 dark:text-zinc-200">{ing.name}</span>
                                                <Plus size={16} className="text-emerald-500" />
                                            </button>
                                        ))
                                    ) : (
                                        <div className="p-5 text-center">
                                            <p className="text-xs text-gray-400">No hay coincidencias en tu catálogo</p>
                                        </div>
                                    )}
                                </div>
                            )}
                        </div>
                        {isSearching && (
                            <div className="fixed inset-0 z-0" onClick={() => setIsSearching(false)} />
                        )}
                    </div>

                    {/* Instructions */}
                    <div className="space-y-2">
                        <label className="text-[10px] text-gray-400 dark:text-zinc-500 font-black uppercase tracking-widest px-1">Pasos de Preparación</label>
                        <textarea
                            value={instructions}
                            onChange={(e) => setInstructions(e.target.value)}
                            className="w-full px-5 py-4 bg-gray-50 dark:bg-zinc-800/50 border border-gray-200 dark:border-zinc-800 rounded-3xl text-sm focus:border-emerald-500 outline-none transition-all dark:text-white resize-none h-32 custom-scrollbar"
                            placeholder="1. Pica la cebolla...&#10;2. Fríe la carne...&#10;3. Sirve con cilantro."
                        />
                    </div>
                </div>

                {/* Footer */}
                <div className="px-6 py-5 border-t border-gray-100 dark:border-white/5 bg-gray-50/50 dark:bg-white/2">
                    <div className="flex items-center gap-4">
                        <button
                            onClick={onClose}
                            className="flex-1 py-3.5 border border-gray-200 dark:border-zinc-800 rounded-2xl text-sm font-bold text-gray-600 dark:text-zinc-400 hover:bg-gray-100 dark:hover:bg-white/5 transition-all"
                        >
                            Cancelar
                        </button>
                        <button
                            onClick={handleSave}
                            disabled={!isFormValid || saving}
                            className="flex-2 py-3.5 bg-emerald-500 hover:bg-emerald-600 disabled:bg-gray-200 dark:disabled:bg-zinc-800 disabled:text-gray-400 dark:disabled:text-zinc-600 disabled:cursor-not-allowed text-white text-sm font-black rounded-2xl transition-all shadow-lg shadow-emerald-500/20 px-8 flex items-center justify-center gap-2"
                        >
                            {saving ? (
                                <span className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                            ) : (
                                isEditing ? "Guardar Cambios" : "Crear Receta"
                            )}
                        </button>
                    </div>
                    {!isFormValid && (
                        <p className="text-[10px] text-gray-400 dark:text-zinc-500 text-center mt-3 flex items-center justify-center gap-1.5 font-medium">
                            <Info size={12} />
                            Ingresa nombre, pasos y al menos 1 ingrediente para continuar
                        </p>
                    )}
                </div>
            </div>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { Sidebar } from "@/features/dashboard/components/Sidebar";
import { Header } from "@/features/dashboard/components/Header";
import AvailableRecipeCard from "@/features/Recipes/components/AvailableRecipeCard";
import HistoryTable from "@/features/Recipes/components/HistoryTable";
import { catalogService } from "@/services/catalog.service";
import {
    HISTORY_RECIPES,
    type AvailableRecipe,
    type HistoryRecipe,
} from "@/features/Recipes/recetasData";
import RecipeModal from "@/features/Recipes/components/RecipeModal";
import RepeatRecipeModal from "@/features/Recipes/components/RepeatRecipeModal";

import { useRouter } from "next/navigation";

export default function RecetasView() {
    const router = useRouter();
    const [recipes, setRecipes] = useState<AvailableRecipe[]>([]);
    const [cookHistory, setCookHistory] = useState<HistoryRecipe[]>([]);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingRecipe, setEditingRecipe] = useState<AvailableRecipe | undefined>();
    const [repeatRecipe, setRepeatRecipe] = useState<HistoryRecipe | undefined>();
    const [showAll, setShowAll] = useState(false);
    const [loadingExternal, setLoadingExternal] = useState(true);

    useEffect(() => {
        const fetchRecipes = async () => {
            const token = localStorage.getItem('token');
            if (!token) return;

            let currentRecipes: AvailableRecipe[] = [];

            // 1. Primero traemos rápido las recetas locales
            const resLocal = await catalogService.getRecipes(token);
            if (resLocal.ok && resLocal.data && resLocal.data.recipes) {
                const mappedLocal = resLocal.data.recipes.map((r: any) => ({
                    id: r.id.toString(),
                    name: r.title,
                    description: r.instructions?.substring(0, 100) + "...",
                    timeMinutes: 30,
                    ingredientsBadge: "LOCAL",
                    imageUrl: r.image_url
                }));
                currentRecipes = mappedLocal;
                setRecipes([...currentRecipes]); // Las mostramos de inmediato para que no se vea vacío
            }

            // 2. Buscamos recetas regionales y aleatorias al mismo tiempo (multitasking)
            const fetchExternal = async () => {
                setLoadingExternal(true);
                try {
                    const [resRegional, resRandom] = await Promise.allSettled([
                        catalogService.getRegionalRecipes(token!),
                        catalogService.getRandomExternalRecipes(token!),
                    ]);

                    let allExternal: any[] = [];
                    if (resRegional.status === 'fulfilled') {
                        if (resRegional.value.ok && resRegional.value.data) {
                            allExternal.push(...(resRegional.value.data.recipes || []));
                        } else if (resRegional.value.status === 401 || resRegional.value.status === 403) {
                            console.error('Error de autenticación en Recetas Regionales:', resRegional.value.status);
                        }
                    }
                    if (resRandom.status === 'fulfilled') {
                        if (resRandom.value.ok && resRandom.value.data) {
                            allExternal.push(...(resRandom.value.data.recipes || []));
                        } else if (resRandom.value.status === 401 || resRandom.value.status === 403) {
                            console.error('Error de autenticación en Recetas Aleatorias:', resRandom.value.status);
                        }
                    }

                    // Quitamos las repetidas por ID
                    const seen = new Set<string>();
                    const deduped = allExternal.filter((r: any) => {
                        const key = r.id || r.idMeal;
                        if (seen.has(key)) return false;
                        seen.add(key);
                        return true;
                    });

                    if (deduped.length > 0) {
                        const mappedExternal = deduped.map((r: any) => ({
                            id: `ext-${r.id || r.idMeal}`,
                            name: r.title || r.strMeal,
                            description: r.category ? `${r.category} | ${r.region || 'Global'}` : (r.strCategory || 'Platillo'),
                            timeMinutes: 45,
                            ingredientsBadge: "THEMEALDB",
                            imageUrl: r.image_url || r.strMealThumb
                        }));
                        setRecipes(prev => {
                            const existingIds = new Set(prev.map(p => p.id));
                            const uniqueNew = mappedExternal.filter((m: any) => !existingIds.has(m.id));
                            return [...prev, ...uniqueNew];
                        });
                    }
                } catch (err) {
                    console.error("Error fetching external recipes:", err);
                } finally {
                    setLoadingExternal(false);
                }
            };
            fetchExternal();
        };
        fetchRecipes();

        // Cargamos el historial de lo que ya se cocinó
        try {
            const saved = localStorage.getItem('biteWise_cookHistory');
            if (saved) setCookHistory(JSON.parse(saved));
        } catch (e) { console.error('Error loading cook history:', e); }
    }, []);

    const handleRecipeClick = (recipe: AvailableRecipe) => {
        router.push(`/recipes-details?id=${recipe.id}`);
    };

    const handleCreate = () => {
        setEditingRecipe(undefined);
        setIsModalOpen(true);
    };

    const handleEdit = (recipe: AvailableRecipe) => {
        setEditingRecipe(recipe);
        setIsModalOpen(true);
    };

    const handleDelete = async (recipeToDelete: AvailableRecipe) => {
        if (recipeToDelete.ingredientsBadge !== "LOCAL") {
            alert("Solo puedes eliminar recetas locales creadas por ti.");
            return;
        }

        if (confirm(`¿Estás seguro de que quieres eliminar la receta "${recipeToDelete.name}"?`)) {
            const token = localStorage.getItem('token');
            if (!token) return;

            try {
                const res = await catalogService.deleteRecipe(Number(recipeToDelete.id), token);
                if (res.ok) {
                    setRecipes(recipes.filter((r: AvailableRecipe) => r.id !== recipeToDelete.id));
                } else {
                    alert("Error al eliminar la receta del servidor.");
                }
            } catch (err) {
                console.error(err);
                alert("Ocurrió un error al intentar eliminar la receta.");
            }
        }
    };

    const handleSaveRecipe = async (savedRecipe: AvailableRecipe) => {
        const token = localStorage.getItem('token');
        if (!token) return;

        try {
            if (editingRecipe) {
                // Lógica para actualizar si se necesitara, por ahora solo crear
                const payload = {
                    title: savedRecipe.name,
                    instructions: savedRecipe.instructions || "",
                    image_url: savedRecipe.imageUrl,
                    ingredients: savedRecipe.ingredients?.map(ing => ({
                        ingredient_id: ing.ingredient_id,
                        required_quantity: ing.required_quantity
                    })) || []
                };
                const res = await catalogService.updateRecipe(Number(savedRecipe.id), payload, token);
                if (res.ok) {
                    // Update local state or re-fetch
                    setRecipes(recipes.map((r: AvailableRecipe) => r.id === savedRecipe.id ? savedRecipe : r));
                }
            } else {
                const payload = {
                    title: savedRecipe.name,
                    instructions: savedRecipe.instructions || "",
                    image_url: savedRecipe.imageUrl,
                    ingredients: savedRecipe.ingredients?.map(ing => ({
                        ingredient_id: ing.ingredient_id,
                        required_quantity: ing.required_quantity
                    })) || []
                };

                const res = await catalogService.createRecipe(payload, token);
                if (res.ok && res.data) {
                    // ¡Listo! Volvemos a pedir las recetas para tener los ID reales y las etiquetas
                    const resLocal = await catalogService.getRecipes(token);
                    if (resLocal.ok && resLocal.data && resLocal.data.recipes) {
                        const mappedLocal = resLocal.data.recipes.map((r: any) => ({
                            id: r.id.toString(),
                            name: r.title,
                            description: r.instructions?.substring(0, 100) + "...",
                            timeMinutes: 30,
                            ingredientsBadge: "LOCAL",
                            imageUrl: r.image_url,
                            instructions: r.instructions,
                            ingredients: r.ingredients?.map((ri: any) => ({
                                ingredient_id: ri.ingredient_id,
                                name: ri.name,
                                required_quantity: ri.quantity,
                                unit: ri.unit
                            }))
                        }));

                        // Mezclamos con las recetas externas que ya teníamos
                        setRecipes(prev => {
                            const external = prev.filter(p => p.ingredientsBadge === "THEMEALDB");
                            return [...mappedLocal, ...external];
                        });
                    }
                } else {
                    alert("Error al guardar la receta en el servidor.");
                }
            }
        } catch (err) {
            console.error(err);
            alert("Error de conexión al guardar la receta.");
        }
    };

    const handleRepeat = (recipe: HistoryRecipe) => {
        setRepeatRecipe(recipe);
    };

    return (
        <div className="flex h-screen overflow-hidden bg-white dark:bg-background-dark">
            <Sidebar activeTab="recetas" />

            <div className="flex-1 flex flex-col overflow-y-auto">
                <Header title="Recetas Disponibles" />

                {/* Contenido principal */}
                <main className="flex-1 px-3 sm:px-4 md:px-8 py-7 flex flex-col gap-8 w-full max-w-7xl mx-auto">

                    {/* Recetas Disponibles */}
                    <section>
                        <div className="flex flex-col sm:flex-row sm:items-baseline justify-between mb-2 sm:mb-1 gap-2 sm:gap-0">
                            <h2 className="text-base font-bold text-gray-900 dark:text-white">Recetas Disponibles</h2>
                            <div className="flex items-center gap-4">
                                <button
                                    onClick={handleCreate}
                                    className="text-xs bg-emerald-500 hover:bg-emerald-600 text-white font-bold px-3 py-1.5 rounded-md transition-colors"
                                >
                                    + Agregar Receta
                                </button>
                                <button
                                    onClick={() => setShowAll(!showAll)}
                                    className="text-xs sm:text-sm text-emerald-600 dark:text-emerald-500 font-semibold hover:text-emerald-700 dark:hover:text-emerald-400 transition-colors"
                                >
                                    {showAll ? 'Ver menos ←' : 'Ver todos →'}
                                </button>
                            </div>
                        </div>
                        <p className="text-xs text-gray-400 dark:text-gray-500 mb-4">
                            Basado en lo que tienes en tu despensa ahora mismo.
                        </p>
                        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
                            {recipes.length === 0 && !loadingExternal ? (
                                <div className="col-span-4 py-12 text-center text-sm text-gray-400 dark:text-gray-500">
                                    No hay recetas disponibles. ¡Agrega la primera!
                                </div>
                            ) : (
                                (showAll ? recipes : recipes.slice(0, 4)).map((recipe: AvailableRecipe) => (
                                    <AvailableRecipeCard
                                        key={recipe.id}
                                        recipe={recipe}
                                        onClick={handleRecipeClick}
                                        onEdit={handleEdit}
                                        onDelete={handleDelete}
                                    />
                                ))
                            )}
                            {loadingExternal && (
                                <div className="col-span-4 py-6 text-center text-sm text-gray-400 dark:text-gray-500 flex items-center justify-center gap-2">
                                    <span className="animate-spin inline-block w-4 h-4 border-2 border-emerald-500 border-t-transparent rounded-full"></span>
                                    Cargando recetas externas...
                                </div>
                            )}
                        </div>
                    </section>

                    {/* Historial de Cocina */}
                    <section>
                        <h2 className="text-base font-bold text-gray-900 dark:text-white mb-1">Historial de Cocina</h2>
                        <p className="text-xs text-gray-400 dark:text-gray-500 mb-4">
                            Tus creaciones recientes. ¿Quieres repetir alguna?
                        </p>
                        <HistoryTable recipes={cookHistory} onRepeat={handleRepeat} />
                    </section>
                </main>

                {/* Modal de Receta */}
                {isModalOpen && (
                    <RecipeModal
                        initialData={editingRecipe}
                        onSave={handleSaveRecipe}
                        onClose={() => setIsModalOpen(false)}
                    />
                )}

                {/* Modal para Repetir Receta del Historial */}
                {repeatRecipe && (
                    <RepeatRecipeModal
                        recipe={repeatRecipe}
                        onClose={() => setRepeatRecipe(undefined)}
                    />
                )}

                {/* Pie de página */}
                <footer className="py-4 text-center">
                    <p className="text-xs text-gray-400">
                        © 2024 <span className="font-semibold">BiteWise</span>. Come mejor, desperdicia menos.
                    </p>
                </footer>
            </div>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from 'react';
import { Sidebar } from './Sidebar';
import { Header } from './Header';
import { useRouter } from 'next/navigation';

const CATEGORY_MAP: Record<string, string[]> = {
  'Desayuno': ['breakfast'],
  'Almuerzo': ['lunch', 'beef', 'chicken', 'pork', 'lamb', 'seafood', 'pasta', 'goat'],
  'Cena': ['dinner', 'side', 'starter'],
  'Snacks': ['snack', 'dessert'],
  'Vegetariano': ['vegetarian', 'vegan'],
  'Saludable': ['miscellaneous', 'healthy'],
};

const CATEGORY_ICONS: Record<string, string> = {
  'chicken': '🍗',
  'beef': '🥩',
  'pasta': '🍝',
  'vegetarian': '🥗',
  'dessert': '🍰',
  'breakfast': '🍳',
  'seafood': '🦐',
  'default': '🍽️',
};

function getRecipeIcon(category: string): string {
  const lower = (category || '').toLowerCase();
  return CATEGORY_ICONS[lower] ?? CATEGORY_ICONS['default'];
}

export default function Dashboard() {
  const router = useRouter();
  const [activeCategory, setActiveCategory] = useState('Todos');
  const [searchQuery, setSearchQuery] = useState('');
  const [recipes, setRecipes] = useState<any[]>([]);
  const [filteredRecipes, setFilteredRecipes] = useState<any[]>([]);
  const [inventoryItems, setInventoryItems] = useState<any[]>([]);
  const [loadingRecipes, setLoadingRecipes] = useState(false);
  const [loadingInventory, setLoadingInventory] = useState(false);

  const CATALOG_URL = process.env.NEXT_PUBLIC_CATALOG_API_URL || 'http://localhost:3002';
  const INVENTORY_URL = process.env.NEXT_PUBLIC_INVENTORY_API_URL || 'http://localhost:3003';

  // Cargamos el inventario desde la API
  useEffect(() => {
    const loadInventory = async () => {
      const token = localStorage.getItem('token');
      if (!token) return;
      setLoadingInventory(true);
      try {
        const res = await fetch(`${INVENTORY_URL}/api/inventory`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        if (res.ok) {
          const data = await res.json();
          setInventoryItems(data.items || []);
        } else if (res.status === 401 || res.status === 403) {
          console.error('Error de autenticación en Inventario:', res.status);
        }
      } catch (e) {
        console.error('Error loading inventory', e);
      } finally {
        setLoadingInventory(false);
      }
    };
    loadInventory();
  }, []);

  // Cargamos las recetas desde el catálogo
  useEffect(() => {
    const loadRecipes = async () => {
      const token = localStorage.getItem('token');
      if (!token) return;
      setLoadingRecipes(true);
      try {
        const res = await fetch(`${CATALOG_URL}/api/recipes`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        if (res.ok) {
          const data = await res.json();
          setRecipes(data.recipes || []);
        }
      } catch (e) {
        console.error('Error loading recipes', e);
      } finally {
        setLoadingRecipes(false);
      }
    };
    loadRecipes();
  }, []);

  // Aplicamos los filtros de categoría y búsqueda cada vez que cambian
  useEffect(() => {
    let result = [...recipes];

    if (activeCategory !== 'Todos') {
      const allowedCats = CATEGORY_MAP[activeCategory] || [activeCategory.toLowerCase()];
      result = result.filter(r => {
        const recipeCat = (r.category || r.title || '').toLowerCase();
        return allowedCats.some(cat => recipeCat.includes(cat));
      });
    }

    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase();
      result = result.filter(r =>
        r.title?.toLowerCase().includes(q) ||
        r.ingredients?.some((ing: any) => ing.name?.toLowerCase().includes(q))
      );
    }

    setFilteredRecipes(result);
  }, [recipes, activeCategory, searchQuery]);

  const categories = ['Todos', 'Desayuno', 'Almuerzo', 'Cena', 'Snacks', 'Vegetariano', 'Saludable'];

  return (
    <div className="flex h-screen overflow-hidden bg-white dark:bg-background-dark">
      <Sidebar activeTab="inicio" />

      <main className="flex-1 flex flex-col overflow-y-auto">
        <Header />

        <div className="p-3 sm:p-4 md:p-8 pt-6 max-w-[1200px] mx-auto w-full space-y-6 md:space-y-8">

          {/* Search + Category Filter */}
          <section className="space-y-4">
            <div className="relative max-w-2xl mx-auto">
              <span translate="no" className="material-symbols-outlined notranslate absolute left-4 top-1/2 -translate-y-1/2 text-[#6c7f6d] dark:text-gray-400">search</span>
              <input
                className="w-full pl-12 pr-4 py-2 sm:py-3 md:py-4 bg-white dark:bg-white/5 border border-[#f1f3f1] dark:border-white/10 rounded-full focus:ring-2 focus:ring-primary focus:border-transparent outline-none transition-all shadow-sm text-sm text-gray-900 dark:text-white dark:placeholder-gray-400"
                placeholder="Buscar recetas, ingredientes..."
                type="text"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>

            <div className="flex flex-wrap items-center justify-start md:justify-center gap-2 overflow-x-auto pb-2 scrollbar-hide">
              {categories.map((cat) => (
                <button
                  key={cat}
                  onClick={() => setActiveCategory(cat)}
                  className={`px-4 py-1.5 md:px-5 md:py-2 rounded-full text-xs md:text-sm font-bold shadow-sm transition-all whitespace-nowrap ${cat === activeCategory
                    ? 'bg-[#4cae4f] text-white border border-[#4cae4f]'
                    : 'bg-white dark:bg-white/5 text-[#6c7f6d] dark:text-gray-300 border border-[#f1f3f1] dark:border-white/10 hover:bg-[#4cae4f] hover:border-[#4cae4f] hover:text-white dark:hover:bg-[#4cae4f] dark:hover:text-white'
                    }`}
                >
                  {cat}
                </button>
              ))}
            </div>
          </section>

          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 md:gap-8">

            {/* Inventory Section */}
            <section className="lg:col-span-1">
              <div className="bg-white dark:bg-white/5 rounded-xl border border-[#f1f3f1] dark:border-white/10 shadow-sm flex flex-col max-h-[480px]">
                <div className="p-5 border-b border-[#f1f3f1] dark:border-white/10 flex justify-between items-center">
                  <h3 className="text-[#131613] dark:text-white text-base font-bold uppercase tracking-tight">Tu Inventario</h3>
                  <span className="text-xs bg-primary/10 text-primary px-2 py-1 rounded font-bold">
                    {loadingInventory ? '...' : `${inventoryItems.length} items`}
                  </span>
                </div>

                <div className="flex-1 overflow-y-auto divide-y divide-[#f1f3f1] dark:divide-white/5">
                  {loadingInventory ? (
                    <div className="p-6 text-center text-sm text-gray-400">Cargando inventario...</div>
                  ) : inventoryItems.length === 0 ? (
                    <div className="p-6 text-center text-sm text-gray-400">
                      No tienes ingredientes en tu inventario aún.
                    </div>
                  ) : (
                    inventoryItems.map((item: any) => {
                      const name = item.ingredients?.name ?? item.name ?? 'Sin nombre';
                      const wpu = Number(item.ingredients?.weight_per_unit || 1);
                      const rawQty = Number(item.current_quantity || 0);
                      const displayQty = wpu > 1 ? rawQty / wpu : rawQty;
                      const finalQty = Math.round(displayQty * 10) / 10;
                      const unit = wpu > 1 ? 'unidades' : (item.ingredients?.unit_default || 'g');

                      return (
                        <div key={item.id} className="flex items-center gap-3 px-5 py-3 hover:bg-background-light dark:hover:bg-white/5 transition-colors">
                          <div className="text-primary flex items-center justify-center rounded-lg bg-primary/10 shrink-0 size-9 text-lg">
                            🥗
                          </div>
                          <div className="flex flex-col flex-1 min-w-0">
                            <p className="text-[#131613] dark:text-white text-sm font-semibold truncate">{name}</p>
                            <p className="text-[#6c7f6d] dark:text-gray-400 text-xs">{finalQty} {unit}</p>
                          </div>
                        </div>
                      );
                    })
                  )}
                </div>

                <div className="p-4 border-t border-[#f1f3f1] dark:border-white/10">
                  <button
                    onClick={() => router.push('/inventory')}
                    className="w-full flex items-center justify-center gap-2 bg-primary text-white py-2.5 rounded-full text-sm font-bold shadow-md hover:shadow-lg transition-all active:scale-[0.98]"
                  >
                    <span translate="no" className="material-symbols-outlined notranslate text-base">open_in_new</span>
                    Ver Inventario Completo
                  </button>
                </div>
              </div>
            </section>

            {/* Recipes Section */}
            <section className="lg:col-span-2">
              <div className="bg-white dark:bg-white/5 rounded-xl border border-[#f1f3f1] dark:border-white/10 shadow-sm flex flex-col max-h-[480px]">
                <div className="p-5 border-b border-[#f1f3f1] dark:border-white/10 flex justify-between items-center">
                  <h3 className="text-[#131613] dark:text-white text-base font-bold uppercase tracking-tight">
                    {activeCategory === 'Todos' ? 'Recetas del Catálogo' : `Recetas: ${activeCategory}`}
                  </h3>
                  <span className="text-xs bg-primary/10 text-primary px-2 py-1 rounded font-bold">
                    {loadingRecipes ? '...' : `${filteredRecipes.length} recetas`}
                  </span>
                </div>

                <div className="flex-1 overflow-y-auto divide-y divide-[#f1f3f1] dark:divide-white/5">
                  {loadingRecipes ? (
                    <div className="p-6 text-center text-sm text-gray-400">Cargando recetas...</div>
                  ) : filteredRecipes.length === 0 ? (
                    <div className="p-6 text-center text-sm text-gray-400">
                      {activeCategory !== 'Todos'
                        ? `No hay recetas de "${activeCategory}" en tu catálogo.`
                        : 'No hay recetas en tu catálogo aún.'}
                    </div>
                  ) : (
                    filteredRecipes.map((recipe: any) => (
                      <div
                        key={recipe.id}
                        onClick={() => router.push(`/kitchen?recipeId=${recipe.id}`)}
                        className="flex items-center gap-4 px-5 py-4 hover:bg-background-light dark:hover:bg-white/5 transition-colors cursor-pointer group"
                      >
                        <div className="size-12 rounded-lg overflow-hidden shrink-0 bg-gray-100 dark:bg-white/10 flex items-center justify-center text-2xl">
                          {recipe.image_url
                            ? <img src={recipe.image_url} alt={recipe.title} className="w-full h-full object-cover" />
                            : getRecipeIcon(recipe.category ?? '')
                          }
                        </div>
                        <div className="flex flex-col flex-1 min-w-0">
                          <p className="text-[#131613] dark:text-white text-sm font-semibold truncate group-hover:text-primary transition-colors">
                            {recipe.title}
                          </p>
                          <p className="text-[#6c7f6d] dark:text-gray-400 text-xs">
                            {recipe.ingredients?.length ?? 0} ingredientes
                            {recipe.servings ? ` · ${recipe.servings} porciones` : ''}
                          </p>
                        </div>
                        <span translate="no" className="material-symbols-outlined notranslate text-gray-300 group-hover:text-primary transition-colors text-xl shrink-0">
                          chevron_right
                        </span>
                      </div>
                    ))
                  )}
                </div>

                <div className="p-4 border-t border-[#f1f3f1] dark:border-white/10">
                  <button
                    onClick={() => router.push('/Recipes')}
                    className="w-full flex items-center justify-center gap-2 bg-primary text-white py-2.5 rounded-full text-sm font-bold shadow-md hover:shadow-lg transition-all active:scale-[0.98]"
                  >
                    <span translate="no" className="material-symbols-outlined notranslate text-base">restaurant_menu</span>
                    Explorar todas las Recetas
                  </button>
                </div>
              </div>
            </section>

          </div>
        </div>

        <footer className="mt-auto p-6 md:p-8 border-t border-[#f1f3f1] dark:border-white/10 text-center">
          <p className="text-xs text-[#6c7f6d] dark:text-gray-400">© 2024 BiteWise. Come mejor, desperdicia menos.</p>
        </footer>
      </main>
    </div>
  );
}

