import Link from 'next/link';
import React, { useEffect, useState } from 'react';

interface HeaderProps {
    title?: string;
}

export function Header({ title = "Dashboard Principal" }: HeaderProps) {
    const [name, setName] = useState("Mi Perfil");
    const [initials, setInitials] = useState("M");

    useEffect(() => {
        const user = localStorage.getItem('user');
        if (user) {
            const userData = JSON.parse(user);
            if (userData.name) {
                setName(userData.name);
                const match = userData.name.match(/(\w)/);
                if (match) setInitials(match[1].toUpperCase());
            }
        }
    }, []);

    return (
        <header className="flex items-center justify-between bg-white dark:bg-background-dark px-8 py-4 border-b border-[#f1f3f1] dark:border-white/10 sticky top-0 z-10 shrink-0">
            <div className="flex items-center gap-4">
                <h2 className="text-xl font-bold dark:text-white">{title}</h2>
            </div>
            <div className="flex items-center gap-3">
                <Link href="/profile" className="flex items-center gap-2 p-1 pr-4 bg-background-light dark:bg-white/5 rounded-full border border-gray-200 dark:border-white/10 text-gray-800 dark:text-gray-200 hover:bg-gray-200 dark:hover:bg-white/10 transition-colors group">
                    <div className="w-8 h-8 rounded-full bg-emerald-500 flex items-center justify-center text-white text-xs font-black shadow-sm group-hover:bg-emerald-600 transition-colors">
                        {initials}
                    </div>
                    <span className="text-sm font-medium">{name}</span>
                </Link>
            </div>
        </header>
    );
}

"use client";

import React, { useState, useEffect } from 'react';
import { Sidebar } from '@/features/dashboard/components/Sidebar';
import InventoryModal, { type InventoryItem } from '@/features/inventory/components/InventoryModal';
import { inventoryService } from '@/services/inventory.service';
import { catalogService } from '@/services/catalog.service';

export default function Inventory() {
    const [ingredients, setIngredients] = useState<InventoryItem[]>([]);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingItem, setEditingItem] = useState<InventoryItem | undefined>();
    const [searchQuery, setSearchQuery] = useState('');

    const loadInventory = async () => {
        const token = localStorage.getItem('token');
        if (!token) return;
        try {
            const res = await inventoryService.getInventory(token);
            if (res.ok && res.data && Array.isArray(res.data.items)) {
                // Mapeamos los datos, asegurándonos de que coincidan con lo que el backend espera
                const weightPerUnit = (i: any) => Number(i.ingredients?.weight_per_unit ?? 1) || 1;
                const mapped = res.data.items.map((item: any) => {
                    const rawQty = Number(item.current_quantity ?? item.quantity ?? 0);
                    const wpu = weightPerUnit(item);
                    const unitQty = wpu > 1 ? rawQty / wpu : rawQty;
                    const unitLabel = wpu > 1 ? 'unidades' : (item.ingredients?.unit_default || 'g');
                    return {
                        id: item.id?.toString() || item.ingredient_id?.toString() || Math.random().toString(),
                        ingredientId: item.ingredient_id?.toString(),
                        name: item.ingredients?.name || item.name || 'Desconocido',
                        category: item.ingredients?.category || item.category || 'General',
                        quantity: `${unitQty % 1 === 0 ? unitQty : unitQty.toFixed(1)} ${unitLabel}`,
                        weightPerUnit: wpu
                    };
                });
                setIngredients(mapped);
            }
        } catch (e) { console.error("Error loading inventory:", e) }
    };

    useEffect(() => {
        loadInventory();
    }, []);

    const handleAdd = () => {
        setEditingItem(undefined);
        setIsModalOpen(true);
    };

    const handleEdit = (id: string, currentName: string) => {
        const itemToEdit = ingredients.find(ing => ing.id === id);
        if (itemToEdit) {
            setEditingItem(itemToEdit);
            setIsModalOpen(true);
        }
    };

    const handleDelete = async (id: string) => {
        if (confirm("¿Estás seguro de que quieres eliminar este ingrediente?")) {
            const token = localStorage.getItem('token');
            if (!token) return;
            try {
                const itemToRemove = ingredients.find(ing => ing.id === id);
                if (!itemToRemove) return;

                const catalogId = Number(itemToRemove.ingredientId);
                const numericQuantity = parseFloat(itemToRemove.quantity) || 0;

                // Si la cantidad es cero o el ID no es válido, lo quitamos de la vista directamente
                if (numericQuantity <= 0 || isNaN(catalogId) || catalogId <= 0) {
                    setIngredients(prev => prev.filter(ing => ing.id !== id));
                    return;
                }

                const res = await inventoryService.deleteInventoryItem(catalogId, numericQuantity, token);
                if (res.ok) {
                    await loadInventory();
                } else {
                    alert(res.error || "No se pudo eliminar el ingrediente.");
                }
            } catch (error) {
                console.error("Error deleting item:", error);
                alert("No se pudo eliminar el ingrediente.");
            }
        }
    };

    const handleSaveItem = async (savedItem: InventoryItem) => {
        const token = localStorage.getItem('token');
        if (!token) return;

        try {
            const numericQuantity = parseFloat(savedItem.quantity) || 1;
            const wpu = savedItem.weightPerUnit || 1;
            let ingredientId = Number(savedItem.id);

            // 1. Primero resolvemos o creamos el ingrediente en el catálogo
            if (editingItem && savedItem.ingredientId) {
                ingredientId = Number(savedItem.ingredientId);

                // ¡Ojo aquí! Si cambiamos el peso, hay que borrarlo del inventario PRIMERO.
                // Esto es porque el servidor calcula cuánto quitar basándose en el peso actual.
                // Si lo actualizamos antes de borrar, las cuentas no van a cuadrar.
                if (wpu !== editingItem.weightPerUnit) {
                    const currentQty = parseFloat(editingItem.quantity) || 0;
                    if (currentQty > 0) {
                        try {
                            await inventoryService.deleteInventoryItem(ingredientId, currentQty, token);
                        } catch (e) {
                            console.warn("No se pudo limpiar el inventario anterior (quizás por el cálculo del peso), seguimos adelante con la actualización.");
                            // Si falla, es probable que ya esté en un estado extraño; forzaremos la nueva cantidad después.
                        }
                    }

                    // Ahora actualizamos el catálogo con toda la información
                    const allIngredientsRes = await catalogService.getIngredients(token);
                    if (allIngredientsRes.ok && Array.isArray(allIngredientsRes.data)) {
                        const currentIng = allIngredientsRes.data.find((i: any) => i.id === ingredientId);
                        if (currentIng) {
                            await catalogService.updateIngredient(ingredientId, {
                                name: currentIng.name,
                                category: currentIng.category,
                                purchase_price: Number(currentIng.purchase_price) || 0.01,
                                purchase_quantity: Number(currentIng.purchase_quantity) || 1,
                                unit_default: currentIng.unit_default || 'g',
                                weight_per_unit: wpu
                            }, token);
                        }
                    }
                }
            } else if (!editingItem || isNaN(ingredientId) || savedItem.id.toString().length > 10) {
                // ... misma lógica para crear ingredientes nuevos ...
                const catRes = await catalogService.createIngredient({
                    name: savedItem.name,
                    category: savedItem.category,
                    purchase_price: 0.05,
                    purchase_quantity: 1,
                    unit_default: 'g',
                    weight_per_unit: wpu
                }, token);

                if (catRes.ok && catRes.data && catRes.data.ingredient) {
                    ingredientId = catRes.data.ingredient.id;
                } else {
                    const allRes = await catalogService.getIngredients(token);
                    if (allRes.ok && allRes.data && Array.isArray(allRes.data)) {
                        const found = allRes.data.find((i: any) => i.name.toLowerCase() === savedItem.name.toLowerCase());
                        if (found) {
                            ingredientId = found.id;
                            await catalogService.updateIngredient(ingredientId, {
                                name: found.name,
                                category: found.category,
                                purchase_price: Number(found.purchase_price) || 0.01,
                                purchase_quantity: Number(found.purchase_quantity) || 1,
                                unit_default: found.unit_default || 'g',
                                weight_per_unit: wpu
                            }, token);
                        } else {
                            throw new Error(`No se pudo acceder al catálogo (Error ${allRes.status}). Esto suele ser un problema de permisos (JWT_SECRET) en el servidor.`);
                        }
                    } else {
                        throw new Error(`El servicio de catálogo no respondió correctamente (Error ${catRes.status}).`);
                    }
                }
            }

            // 2. Por último, guardamos la nueva cantidad en el inventario.
            // Como ya limpiamos lo anterior si cambió el peso, ahora se guardará con los gramos correctos.
            const res = await inventoryService.createInventoryItem({
                ingredient_id: ingredientId,
                quantity: numericQuantity
            }, token);

            if (res.ok) {
                await loadInventory();
                setIsModalOpen(false);
            } else {
                alert("Hubo un error al guardar el ingrediente en el inventario.");
            }
        } catch (error) {
            console.error("Error saving inventory item:", error);
            alert("No se pudo guardar el ingrediente");
        }
    };

    return (
        <div className="flex h-screen overflow-hidden bg-white dark:bg-background-dark">
            <Sidebar activeTab="inventario" />
            <main className="flex-1 flex flex-col overflow-y-auto">
                <div className="p-3 sm:p-4 md:p-8 pt-16 max-w-[1200px] mx-auto w-full flex-1 flex flex-col">
                    {/* Encabezado principal */}
                    <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 mb-6 md:mb-8">
                        <div>
                            <h1 className="text-2xl md:text-3xl font-black text-[#131613] dark:text-white mb-1">Inventario</h1>
                            <p className="text-sm md:text-base text-[#6c7f6d] dark:text-gray-400">Gestiona y monitorea la frescura de tus ingredientes.</p>
                        </div>

                        <div className="flex flex-wrap items-center gap-2 md:gap-3">
                            {/* Buscador */}
                            <div className="relative flex-1 min-w-[200px]">
                                <span translate="no" className="material-symbols-outlined notranslate absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 text-[20px]">search</span>
                                <input
                                    type="text"
                                    placeholder="Buscar ingrediente..."
                                    value={searchQuery}
                                    onChange={(e) => setSearchQuery(e.target.value)}
                                    className="pl-11 pr-4 py-2 border border-gray-200 dark:border-zinc-800 rounded-full text-sm focus:outline-none focus:ring-2 focus:ring-emerald-500 w-full transition-all bg-white dark:bg-transparent text-gray-900 dark:text-white"
                                />
                            </div>

                            {/* Botón para agregar */}
                            <button onClick={handleAdd} className="flex items-center gap-2 px-4 py-2 bg-emerald-500 hover:bg-emerald-600 text-white rounded-full text-sm font-bold shadow-md transition-colors">
                                <span translate="no" className="material-symbols-outlined notranslate text-[18px]">add</span>
                                <span className="hidden sm:inline">Agregar</span>
                            </button>
                        </div>
                    </div>

                    {/* Estructura de la tabla */}
                    <div className="flex-1 bg-white dark:bg-zinc-900 border border-gray-100 dark:border-zinc-800 rounded-2xl flex flex-col overflow-hidden shadow-sm">
                        <div className="overflow-x-auto flex-1 flex flex-col">
                            <div className="flex-1 flex flex-col">
                                {/* Encabezados de la tabla */}
                                <div className="flex flex-col sm:grid sm:grid-cols-4 px-6 md:px-8 py-4 border-b border-gray-100 dark:border-zinc-800 bg-gray-50/50 dark:bg-zinc-900/50 text-xs font-bold text-gray-400 tracking-wider">
                                    <div>INGREDIENTE</div>
                                    <div>CATEGORÍA</div>
                                    <div>CANTIDAD</div>
                                    <div className="text-left sm:text-right">ACCIONES</div>
                                </div>

                                {/* Contenido */}
                                <div className="flex-1 overflow-y-auto flex flex-col">
                                    {ingredients.length === 0 ? (
                                        <div className="flex-1 flex items-center justify-center p-8 text-center">
                                            <p className="text-gray-400 text-sm">No hay ingredientes en el inventario.</p>
                                        </div>
                                    ) : (
                                        ingredients
                                            .filter(ing => {
                                                if (!searchQuery.trim()) return true;
                                                const q = searchQuery.toLowerCase();
                                                return ing.name.toLowerCase().includes(q) || ing.category.toLowerCase().includes(q);
                                            })
                                            .map((ing) => (
                                                <div key={ing.id} className="flex flex-col sm:grid sm:grid-cols-4 px-6 md:px-8 py-4 border-b border-gray-50 dark:border-zinc-800/50 items-start sm:items-center text-sm group hover:bg-gray-50 dark:hover:bg-zinc-800/30 transition-colors gap-2 sm:gap-0">
                                                    <div className="font-medium text-gray-900 dark:text-gray-100 sm:col-span-1">
                                                        <span className="sm:hidden font-bold text-gray-500 mr-2">Ingrediente:</span>
                                                        {ing.name}
                                                    </div>
