"use client";

import React, { useState, useEffect } from "react";
import { Bell, Search } from "lucide-react";
import type { Recipe } from "@/types/global";
import { Sidebar } from "@/features/dashboard/components/Sidebar";
import { Header } from "@/features/dashboard/components/Header";
import RecipeCard from "./RecipeCard";
import RecipeDetail from "./RecipeDetail";
import { catalogService } from "@/services/catalog.service";
import { inventoryService } from "@/services/inventory.service";
import { useSearchParams, useRouter } from "next/navigation";

interface CookingSession {
    recipeId: string;
    recipeName: string;
    imageUrl: string;
    totalSteps: number;
    completedStepIds: string[];
    isCompleted: boolean;
    lastUpdated: number;
    instructions: string;
}

export default function CocinaView() {
    const searchParams = useSearchParams();
    const recipeIdParam = searchParams.get('recipeId');

    const [recipes, setRecipes] = useState<Recipe[]>([]);
    const [selectedRecipe, setSelectedRecipe] = useState<Recipe | null>(null);
    const [searchQuery, setSearchQuery] = useState("");
    const [loading, setLoading] = useState(true);
    const [cookingSessions, setCookingSessions] = useState<CookingSession[]>([]);
    const router = useRouter();

    // Cargamos las sesiones de cocina que guardamos en el navegador
    useEffect(() => {
        try {
            const raw = localStorage.getItem('biteWise_cookingSessions');
            if (raw) {
                const sessions: Record<string, CookingSession> = JSON.parse(raw);
                const list = Object.values(sessions)
                    .sort((a, b) => b.lastUpdated - a.lastUpdated);
                setCookingSessions(list);
            }
        } catch { /* si falla, no pasa nada */ }
    }, []);

    useEffect(() => {
        const fetchMatchingRecipes = async () => {
            const token = localStorage.getItem('token');
            if (!token) {
                setLoading(false);
                return;
            }
            // Traemos las recetas y el inventario para ver qué podemos cocinar
            const [res, invRes] = await Promise.all([
                catalogService.getMatchingRecipes(token),
                inventoryService.getInventory(token)
            ]);

            let finalRecipes: Recipe[] = [];
            const inventory = (invRes.ok && Array.isArray((invRes.data as any)?.items)) ? (invRes.data as any).items : [];
            const inventoryMap = new Map<number, number>(inventory.map((item: any) => [
                Number(item.ingredient_id || item.ingredients?.id),
                Number(item.current_quantity || item.quantity || 0)
            ]));

            if (res.ok && res.data && Array.isArray(res.data.data)) {
                // Mapeamos las recetas que coinciden
                finalRecipes = res.data.data.map((r: any) => ({
                    id: r.id.toString(),
                    name: r.title,
                    time: r.time_minutes || 30, // Si no hay tiempo, ponemos 30 por defecto
                    calories: 400,
                    difficulty: r.difficulty || "Media",
                    servings: r.servings || 2,
                    instructions: r.instructions,
                    hasAllIngredients: r.missingCount === 0,
                    missingIngredients: r.missingCount > 0 ? ["Faltan " + r.missingCount + " ingredientes"] : [],
                    imageUrl: r.image_url,
                    ingredients: r.ingredients?.map((i: any) => {
                        const ingId = Number(i.ingredient_id);
                        const requiredQty = Number(i.required_quantity || i.quantity || 1);
                        const availableQty = Number(inventoryMap.get(ingId) || 0);
                        return {
                            id: `i-${ingId}`,
                            name: i.name || i.Ingredient?.name || 'Desconocido',
                            amount: requiredQty,
                            unit: i.unit || i.ingredient?.unit_default || 'g',
                            available: availableQty >= requiredQty
                        };
                    }) || []
                }));
            }

            if (recipeIdParam) {
                const preset = finalRecipes.find(r => r.id === recipeIdParam);
                if (preset) {
                    setSelectedRecipe(preset);
                } else {
                    // Si no es una receta que coincida exactamente, buscamos sus detalles
                    // para que el usuario pueda ver qué ingredientes le faltan
                    try {
                        if (recipeIdParam.startsWith('ext-')) {
                            const realId = recipeIdParam.replace('ext-', '');
                            const extRes = await fetch(`https://www.themealdb.com/api/json/v1/1/lookup.php?i=${realId}`);
                            const data = await extRes.json();
                            if (data.meals && data.meals[0]) {
                                const m = data.meals[0];

                                const mappedExtIngredients: typeof finalRecipes[0]['ingredients'] = [];
                                for (let i = 1; i <= 20; i++) {
                                    const ing = m[`strIngredient${i}`];
                                    const measure = m[`strMeasure${i}`];
                                    if (ing && ing.trim()) {
                                        mappedExtIngredients.push({
                                            id: `ext-ing-${i}`,
                                            name: ing.trim(),
                                            amount: measure ? measure.trim() : "1",
                                            unit: "",
                                            available: false
                                        });
                                    }
                                }

                                const extRecipe: Recipe = {
                                    id: `ext-${m.idMeal}`,
                                    name: m.strMeal,
                                    time: 45,
                                    calories: 500,
                                    difficulty: "Media",
                                    servings: 2,
                                    instructions: m.strInstructions,
                                    hasAllIngredients: false,
                                    missingIngredients: ["Faltan ingredientes del catálogo global"],
                                    imageUrl: m.strMealThumb,
                                    ingredients: mappedExtIngredients,
                                    externalMealData: m  // Guardamos los datos de TheMealDB por si queremos importarlos luego
                                };
                                finalRecipes = [extRecipe, ...finalRecipes];
                                setSelectedRecipe(extRecipe);
                            }
                        } else {
                            const localRes = await catalogService.getRecipeById(Number(recipeIdParam), undefined, token);
                            if (localRes.ok && localRes.data && localRes.data.recipe) {
                                const r = localRes.data.recipe as any;

                                // Aseguramos que los ingredientes lleguen bien desde la base de datos local
                                const rawIngredients = r.ingredients || r.RecipeIngredients || r.recipe_ingredients || [];

                                const localRecipe: Recipe = {
                                    id: r.id.toString(),
                                    name: r.title,
                                    time: r.time_minutes || 30,
                                    calories: 400,
                                    difficulty: r.difficulty || "Media",
                                    servings: 2,
                                    instructions: r.instructions,
                                    hasAllIngredients: false,
                                    missingIngredients: ["Faltan ingredientes"],
                                    imageUrl: r.image_url,
                                    ingredients: rawIngredients.map((i: any) => {
                                        const ingId = Number(i.ingredient_id || i.id);
                                        const requiredQty = Number(i.required_quantity || i.quantity || 1);
                                        const availableQty = Number(inventoryMap.get(ingId) || 0);
                                        return {
                                            id: `i-${ingId}`,
                                            name: i.name || i.Ingredient?.name || i.ingredient?.name || 'Desconocido',
                                            amount: requiredQty,
                                            unit: i.unit || i.ingredient?.unit_default || 'g',
                                            available: availableQty >= requiredQty
                                        };
                                    })
                                };
                                finalRecipes = [localRecipe, ...finalRecipes];
                                setSelectedRecipe(localRecipe);
                            }
                        }
                    } catch (e) {
                        console.error("No se pudo obtener la receta preseleccionada", e);
                    }
                }
            } else {
                if (finalRecipes.length > 0) setSelectedRecipe(finalRecipes[0]);
            }

            // Actualizamos la lista de recetas
            setRecipes(finalRecipes);
            setLoading(false);
        };
        fetchMatchingRecipes();
    }, []);

    const filteredRecipes = recipes.filter(r => r.name.toLowerCase().includes(searchQuery.toLowerCase()));

    return (
        <div className="flex min-h-screen bg-background-light dark:bg-background-dark">
            <Sidebar activeTab="cocina" />

            <main className="flex-1 flex flex-col overflow-hidden">
                <Header title="Tu Cocina" />

                {/* Contenido principal */}
                <div className="flex-1 p-6 overflow-hidden flex flex-col md:flex-row gap-6">
                    {loading ? (
                        <div className="w-full flex justify-center items-center">
                            <span className="text-gray-500">Buscando qué puedes cocinar...</span>
                        </div>
                    ) : recipes.length === 0 && cookingSessions.length === 0 ? (
                        <div className="w-full h-full bg-white dark:bg-white/5 rounded-2xl border border-gray-100 dark:border-white/10 shadow-sm flex items-center justify-center">
                            <div className="text-center">
                                <div className="text-4xl mb-4">🍳</div>
                                <h3 className="text-lg font-bold text-gray-900 dark:text-white">Tu inventario no coincide con ninguna receta</h3>
                                <p className="text-sm text-gray-500 mt-2 max-w-sm">
                                    Agrega más ingredientes a tu inventario para ver sugerencias de recetas.
                                </p>
                            </div>
                        </div>
                    ) : (
                        <>
                            <div className="w-full md:w-1/3 flex flex-col gap-4 overflow-y-auto">
                                {/* Sesiones de cocina activas */}
                                {cookingSessions.length > 0 && (
                                    <div className="space-y-2">
                                        <p className="text-[10px] uppercase tracking-wider text-gray-400 font-bold px-1">
                                            {cookingSessions.some(s => s.isCompleted) && cookingSessions.some(s => !s.isCompleted)
                                                ? "Sesiones de cocina"
                                                : cookingSessions.every(s => s.isCompleted)
                                                    ? "Recetas completadas"
                                                    : "Cocinando ahora"}
                                        </p>
                                        {cookingSessions.map(session => {
                                            const progress = session.totalSteps > 0
                                                ? Math.round((session.completedStepIds.length / session.totalSteps) * 100)
                                                : 0;
                                            return (
                                                <button
                                                    key={`session-${session.recipeId}`}
                                                    onClick={() => router.push(`/step-by-step-kitchen?recipeId=${session.recipeId}&name=${encodeURIComponent(session.recipeName)}`)}
                                                    className={`w-full text-left px-4 py-3 rounded-xl transition-all duration-150 border ${session.isCompleted
                                                        ? "border-green-200 dark:border-green-800 bg-green-50/50 dark:bg-green-900/10"
                                                        : "border-orange-200 dark:border-orange-800 bg-orange-50/50 dark:bg-orange-900/10"
                                                        } hover:shadow-sm`}
                                                >
                                                    <div className="flex items-center gap-3">
                                                        {session.imageUrl ? (
                                                            <img src={session.imageUrl} alt={session.recipeName} className="w-10 h-10 rounded-lg object-cover flex-shrink-0" />
                                                        ) : (
                                                            <div className="w-10 h-10 rounded-lg bg-gray-200 dark:bg-white/10 flex items-center justify-center flex-shrink-0 text-lg">
                                                                {session.isCompleted ? "✅" : "🍳"}
                                                            </div>
                                                        )}
                                                        <div className="flex-1 min-w-0">
                                                            <p className="text-sm font-semibold truncate text-gray-800 dark:text-gray-200">{session.recipeName}</p>
                                                            <div className="flex items-center gap-2 mt-1">
                                                                <div className="flex-1 h-1.5 bg-gray-200 dark:bg-zinc-700 rounded-full overflow-hidden">
                                                                    <div className={`h-full rounded-full transition-all ${session.isCompleted ? 'bg-green-500' : 'bg-orange-400'}`} style={{ width: `${progress}%` }} />
                                                                </div>
                                                                <span className="text-[10px] text-gray-500 font-medium whitespace-nowrap">
                                                                    {session.isCompleted ? "Hecha ✓" : `${session.completedStepIds.length}/${session.totalSteps}`}
                                                                </span>
                                                            </div>
                                                        </div>
                                                    </div>
                                                </button>
                                            );
                                        })}

                                        <div className="border-b border-gray-100 dark:border-white/10 my-1" />
                                    </div>
                                )}

                                <div className="relative">
                                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                                    <input
                                        type="text"
                                        placeholder="Buscar receta sugerida..."
                                        value={searchQuery}
                                        onChange={(e) => setSearchQuery(e.target.value)}
                                        className="w-full pl-10 pr-4 py-2 border border-[#f1f3f1] dark:border-white/10 bg-white dark:bg-white/5 text-gray-900 dark:text-white rounded-lg text-sm"
                                    />
                                </div>
                                {filteredRecipes.map(recipe => (
                                    <RecipeCard
                                        key={recipe.id}
                                        recipe={recipe}
                                        isSelected={selectedRecipe?.id === recipe.id}
                                        onSelect={setSelectedRecipe}
                                    />
                                ))}
                            </div>
                            <div className="w-full md:w-2/3 h-full overflow-hidden bg-white dark:bg-transparent rounded-2xl border border-gray-100 dark:border-white/10 shadow-sm">
                                {selectedRecipe ? (
                                    <RecipeDetail recipe={selectedRecipe} />
                                ) : (
                                    <div className="w-full h-full flex items-center justify-center text-gray-500">
                                        Selecciona una receta para ver sus detalles
                                    </div>
                                )}
                            </div>
                        </>
                    )}
                </div>
            </main>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { Mail, Wallet, Calendar, Pencil, PencilLine, Loader2 } from "lucide-react";
import { Sidebar } from "@/features/dashboard/components/Sidebar";
import { Header } from "@/features/dashboard/components/Header";
import EditBudgetModal from "@/features/profile/components/EditBudgetModal";
import EditProfileModal from "@/features/profile/components/EditProfileModal";
import type { UserProfile } from "@/features/profile/perfilTypes";
import { usersService } from "@/services/users.service";

function getInitials(name: string): string {
    if (!name) return "?";
    return name.split(' ')
        .map(n => n[0])
        .filter(c => !!c)
        .join('')
        .substring(0, 2)
        .toUpperCase() || "?";
}

function formatDate(isoDate: string): string {
    try {
        const date = new Date(isoDate);
        return date.toLocaleDateString("es-MX", { day: "numeric", month: "short", year: "numeric" });
    } catch {
        return isoDate;
    }
}

export default function ProfileView() {
    const [profile, setProfile] = useState<UserProfile | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState("");
    const [showBudgetModal, setShowBudgetModal] = useState(false);
    const [showProfileModal, setShowProfileModal] = useState(false);

    const fetchProfile = async () => {
        const token = localStorage.getItem("token");
        const userId = localStorage.getItem("userId");
        if (!token || !userId) {
            setError("No se encontró sesión activa. Inicia sesión de nuevo.");
            setLoading(false);
            return;
        }

        try {
            const res = await usersService.getProfile(userId, token);
            if (res.ok && res.data && res.data.user) {
                const u = res.data.user;
                const budgetNum = u.weekly_budget !== undefined && u.weekly_budget !== null
                    ? Number(u.weekly_budget)
                    : 0;

                // Load stats from localStorage with multiple possible keys for robustness
                let recipeCount = 0;
                let listCount = 0;
                let savingsPercent = 0;

                try {
                    const cookHistory = JSON.parse(localStorage.getItem('biteWise_cookHistory') || '[]');
                    recipeCount = Array.isArray(cookHistory) ? cookHistory.length : 0;
                } catch (e) { console.error("Error parsing cookHistory", e); }

                try {
                    const sessionsRaw = localStorage.getItem('biteWise_cookingSessions');
                    if (sessionsRaw) {
                        const sessions = JSON.parse(sessionsRaw);
                        const sessionValues = Object.values(sessions);
                        const sessionsStarted = sessionValues.length;
                        const sessionsDone = sessionValues.filter((s: any) => s.isCompleted).length;
                        // We use whichever is higher between the history and started sessions
                        recipeCount = Math.max(recipeCount, sessionsStarted, sessionsDone);
                    }
                } catch (e) { console.error("Error parsing cookingSessions", e); }

                try {
                    const lists = JSON.parse(localStorage.getItem('biteWise_shoppingLists') || '[]');
                    listCount = Array.isArray(lists) ? lists.length : 0;
                } catch (e) { console.error("Error parsing shoppingLists", e); }

                // Basic savings logic
                if (recipeCount > 0) {
                    savingsPercent = Math.min(45, 12 + (recipeCount * 2));
                }

                setProfile({
                    id: u.id,
                    name: u.name,
                    initials: getInitials(u.name),
                    plan: u.role === "admin" ? "Admin" : "Cliente",
                    role: u.role,
                    email: u.email,
                    weeklyBudget: budgetNum,
                    currency: "MXN",
                    memberSince: u.created_at ? formatDate(u.created_at) : "—",
                    stats: {
                        recipes: recipeCount,
                        lists: listCount,
                        savings: savingsPercent,
                    },
                });
            } else {
                setError(res.error || "No se pudo obtener el perfil.");
            }
        } catch (e) {
            console.error("Error fetching profile:", e);
            setError("Error de conexión al obtener el perfil.");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchProfile();
    }, []);

    const handleSaveBudget = async (newBudget: number) => {
        const token = localStorage.getItem("token");
        const userId = profile?.id;
        if (!token || !userId) return;

        try {
            const res = await usersService.updateProfile(userId, { weekly_budget: newBudget }, token);
            if (res.ok) {
                setProfile((prev) => prev ? { ...prev, weeklyBudget: newBudget } : prev);
            } else {
                alert(res.error || "No se pudo actualizar el presupuesto.");
            }
        } catch {
            alert("Error de conexión al actualizar el presupuesto.");
        }
    };

    const handleSaveProfile = async (updates: Partial<UserProfile>) => {
        const token = localStorage.getItem("token");
        const userId = profile?.id;
        if (!token || !userId) return;

        try {
            const res = await usersService.updateProfile(userId, { name: updates.name }, token);
            if (res.ok) {
                setProfile((prev) => {
                    if (!prev) return prev;
                    const newName = updates.name || prev.name;
                    return {
                        ...prev,
                        ...updates,
                        name: newName,
                        initials: getInitials(newName),
                    };
                });
                // Update localStorage too
                const stored = localStorage.getItem("user");
                if (stored) {
                    const user = JSON.parse(stored);
                    user.name = updates.name || user.name;
                    localStorage.setItem("user", JSON.stringify(user));
                }
            } else {
                alert(res.error || "No se pudo actualizar el perfil.");
            }
        } catch {
            alert("Error de conexión al actualizar el perfil.");
        }
    };

    const formatBudget = (amount: number) =>
        amount > 0
            ? `$${amount.toLocaleString("es-MX", { minimumFractionDigits: 2 })} ${profile?.currency || "MXN"}`
            : "—";

    if (loading) {
        return (
            <div className="flex h-screen overflow-hidden bg-white dark:bg-background-dark">
                <Sidebar activeTab="perfil" />
                <div className="flex-1 flex flex-col overflow-y-auto">
                    <Header title="Mi Perfil" />
                    <main className="flex-1 flex items-center justify-center">
                        <div className="flex flex-col items-center gap-3">
                            <Loader2 className="w-8 h-8 text-emerald-500 animate-spin" />
                            <p className="text-sm text-gray-500">Cargando perfil...</p>
                        </div>
                    </main>
                </div>
            </div>
        );
    }

    if (error || !profile) {
        return (
            <div className="flex h-screen overflow-hidden bg-white dark:bg-background-dark">
                <Sidebar activeTab="perfil" />
                <div className="flex-1 flex flex-col overflow-y-auto">
                    <Header title="Mi Perfil" />
                    <main className="flex-1 flex items-center justify-center p-4">
                        <div className="text-center max-w-sm">
                            <div className="text-4xl mb-4">⚠️</div>
                            <h3 className="text-lg font-bold text-gray-900 dark:text-white mb-2">Error al cargar perfil</h3>
                            <p className="text-sm text-gray-500 mb-4">{error || "No se pudieron obtener los datos."}</p>
                            <button
                                onClick={() => { setLoading(true); setError(""); fetchProfile(); }}
                                className="px-4 py-2 bg-emerald-500 text-white text-sm font-bold rounded-xl hover:bg-emerald-600 transition-colors"
                            >
                                Reintentar
                            </button>
                        </div>
                    </main>
                </div>
            </div>
        );
    }

    return (
        <div className="flex h-screen overflow-hidden bg-white dark:bg-background-dark">
            <Sidebar activeTab="perfil" />

            <div className="flex-1 flex flex-col overflow-y-auto">
                <Header title="Mi Perfil" />

                {/* Main content */}
                <main className="flex-1 flex items-start justify-center p-4 md:p-8">
                    <div className="w-full max-w-sm mt-8">
                        {/* Profile card */}
                        <div className="bg-white dark:bg-background-dark border border-gray-200 dark:border-white/10 rounded-2xl shadow-sm overflow-hidden">
                            {/* Avatar + name */}
                            <div className="flex flex-col items-center pt-8 pb-5 px-6 border-b border-gray-100 dark:border-white/10">
                                <div className="relative mb-3">
                                    <div className="w-20 h-20 rounded-full bg-emerald-500 flex items-center justify-center shadow-md">
                                        <span className="text-white text-2xl font-bold">
                                            {profile.initials || "?"}
                                        </span>
                                    </div>
                                    <button
                                        onClick={() => setShowProfileModal(true)}
                                        className="absolute bottom-0 right-0 w-6 h-6 bg-white dark:bg-zinc-800 border border-gray-200 dark:border-zinc-700 rounded-full flex items-center justify-center shadow-sm hover:bg-gray-50 dark:hover:bg-zinc-700 transition-colors"
                                    >
                                        <Pencil size={11} className="text-gray-500 dark:text-gray-400" />
                                    </button>
                                </div>
                                <h2 className="text-base font-bold text-gray-900 dark:text-white">
                                    {profile.name || "—"}
                                </h2>
                                <span className="text-xs text-emerald-600 dark:text-emerald-500 font-semibold mt-0.5">
                                    {profile.plan || "—"}
                                </span>
                            </div>

                            {/* Info fields */}
                            <div className="px-6 py-4 space-y-4 border-b border-gray-100 dark:border-white/10 bg-white dark:bg-white/5">
                                {/* Email */}
                                <div className="flex items-center gap-3">
                                    <Mail size={15} className="text-gray-400 dark:text-gray-500 shrink-0" />
                                    <div className="min-w-0">
                                        <p className="text-[10px] text-gray-400 dark:text-gray-500 uppercase tracking-wider font-medium">
                                            Email
                                        </p>
                                        <p className="text-sm text-gray-700 dark:text-gray-300 truncate">
                                            {profile.email || "—"}
                                        </p>
                                    </div>
                                </div>

                                {/* Weekly Budget */}
                                <div className="flex items-center gap-3">
                                    <Wallet size={15} className="text-gray-400 dark:text-gray-500 shrink-0" />
                                    <div className="flex-1 min-w-0">
                                        <p className="text-[10px] text-gray-400 dark:text-gray-500 uppercase tracking-wider font-medium">
                                            Presupuesto Semanal
                                        </p>
                                        <p className="text-sm text-gray-700 dark:text-gray-300">{formatBudget(profile.weeklyBudget)}</p>
                                    </div>
                                    <button
                                        onClick={() => setShowBudgetModal(true)}
                                        className="flex items-center gap-1.5 text-xs text-emerald-600 dark:text-emerald-500 font-semibold hover:text-emerald-700 dark:hover:text-emerald-400 transition-colors px-2 py-1 rounded-lg hover:bg-emerald-50 dark:hover:bg-emerald-500/10"
                                    >
                                        <PencilLine size={12} />
                                        Editar
                                    </button>
                                </div>

                                {/* Member since */}
                                <div className="flex items-center gap-3">
                                    <Calendar size={15} className="text-gray-400 dark:text-gray-500 shrink-0" />
                                    <div className="min-w-0">
                                        <p className="text-[10px] text-gray-400 dark:text-gray-500 uppercase tracking-wider font-medium">
                                            Cuenta
                                        </p>
                                        <p className="text-sm text-gray-700 dark:text-gray-300">
                                            {profile.memberSince ? `Miembro desde: ${profile.memberSince}` : "—"}
                                        </p>
                                    </div>
                                </div>
                            </div>

                            {/* Edit profile button */}
                            <div className="px-6 py-4 border-b border-gray-100 dark:border-white/10">
                                <button
                                    onClick={() => setShowProfileModal(true)}
                                    className="w-full py-2.5 bg-emerald-500 hover:bg-emerald-600 text-white text-sm font-bold rounded-xl transition-colors shadow-sm shadow-emerald-200 dark:shadow-none flex items-center justify-center gap-2"
                                >
                                    <Pencil size={14} />
                                    Editar Perfil
                                </button>
                            </div>

                            {/* Stats */}
                            <div className="grid grid-cols-1 sm:grid-cols-3 divide-x divide-gray-100 dark:divide-white/10 px-2 py-4">
                                <div className="flex flex-col items-center gap-0.5 px-4">
                                    <span className="text-lg font-bold text-gray-900 dark:text-white">
                                        {profile.stats.recipes || "—"}
                                    </span>
                                    <span className="text-[10px] text-gray-400 dark:text-gray-500 uppercase tracking-wide">
                                        Recetas
                                    </span>
                                </div>
                                <div className="flex flex-col items-center gap-0.5 px-4">
                                    <span className="text-lg font-bold text-gray-900 dark:text-white">
                                        {profile.stats.lists || "—"}
                                    </span>
                                    <span className="text-[10px] text-gray-400 dark:text-gray-500 uppercase tracking-wide">
                                        Listas
                                    </span>
                                </div>
                                <div className="flex flex-col items-center gap-0.5 px-4">
                                    <span className="text-lg font-bold text-gray-900 dark:text-white">
                                        {profile.stats.savings > 0 ? `${profile.stats.savings}%` : "—"}
                                    </span>
                                    <span className="text-[10px] text-gray-400 dark:text-gray-500 uppercase tracking-wide">
                                        Ahorro
                                    </span>
                                </div>
                            </div>
                        </div>
                    </div>
                </main>

                {/* Edit Budget Modal */}
                {showBudgetModal && profile && (
                    <EditBudgetModal
                        currentBudget={profile.weeklyBudget}
                        currency={profile.currency}
                        onSave={handleSaveBudget}
                        onClose={() => setShowBudgetModal(false)}
                    />
                )}

                {/* Edit Profile Modal */}
                {showProfileModal && profile && (
                    <EditProfileModal
                        currentProfile={profile}
                        onSave={handleSaveProfile}
                        onClose={() => setShowProfileModal(false)}
                    />
                )}
            </div>
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { ArrowLeft, Clock, Users, ShoppingBag, PlayCircle } from "lucide-react";
import { Sidebar } from "@/features/dashboard/components/Sidebar";
import { Header } from "@/features/dashboard/components/Header";
import IngredientRow from "@/features/recipes-details/components/IngredientRow";
import { catalogService } from "@/services/catalog.service";
import { useSearchParams, useRouter } from "next/navigation";

export default function RecipeDetailView() {
    const searchParams = useSearchParams();
    const router = useRouter();
    const recipeId = searchParams.get('id');
    const [recipe, setRecipe] = useState<any>(null);

    useEffect(() => {
        const fetchRecipe = async () => {
            if (!recipeId) return;

            const token = localStorage.getItem('token');

            // Fetch inventory once to check ingredient availability
            let inventoryItems: any[] = [];
            try {
                const invRes = await fetch(`${process.env.NEXT_PUBLIC_INVENTORY_API_URL || 'http://localhost:3003'}/api/inventory`, {
                    headers: { Authorization: `Bearer ${token}` }
                });
                if (invRes.ok) {
                    const invData = await invRes.json();
                    inventoryItems = invData.items || [];
                }
            } catch (e) {
                console.warn("Could not fetch inventory for availability check", e);
            }

            const inventoryNames = new Set(inventoryItems.map((item: any) =>
                (item.ingredients?.name || item.name || '').toLowerCase().trim()
            ));

            // Handle external recipes from TheMealDB
            if (recipeId.toString().startsWith('ext-')) {
                const realId = recipeId.toString().replace('ext-', '');
                try {
                    const res = await fetch(`https://www.themealdb.com/api/json/v1/1/lookup.php?i=${realId}`);
                    const data = await res.json();
                    if (data.meals && data.meals[0]) {
                        const m = data.meals[0];
                        const ingredients = [];
                        for (let i = 1; i <= 20; i++) {
                            const ingName = m[`strIngredient${i}`];
                            const ingMeasure = m[`strMeasure${i}`];
                            if (ingName && ingName.trim() !== '') {
                                const inInventory = inventoryNames.has(ingName.trim().toLowerCase());
                                ingredients.push({
                                    id: `ext-ing-${i}`,
                                    name: ingName.trim(),
                                    amount: ingMeasure ? ingMeasure.trim() : '',
                                    inInventory
                                });
                            }
                        }

                        const inventoryCount = ingredients.filter(i => i.inInventory).length;
                        setRecipe({
                            id: `ext-${m.idMeal}`,
                            name: m.strMeal,
                            tag: "GLOBAL",
                            portions: 2,
                            timeMinutes: 45,
                            inventoryCount,
                            totalCount: ingredients.length,
                            imageUrl: m.strMealThumb,
                            ingredients
                        });
                    }
                } catch (err) {
                    console.error("Error fetching external recipe", err);
                }
                return;
            }

            // Handle local recipes from microservice
            const res = await catalogService.getRecipeById(Number(recipeId), undefined, token || undefined);
            if (res.ok && res.data && res.data.recipe) {
                const r = res.data.recipe;
                const rawIngredients = r.ingredients || [];
                const mappedIngredients = rawIngredients.map((ing: any) => {
                    const name = ing.ingredient?.name || ing.name || '';
                    const inInventory = inventoryNames.has(name.toLowerCase().trim());
                    return {
                        id: (ing.ingredient_id || ing.id || '').toString(),
                        name,
                        amount: `${ing.required_quantity || ing.quantity || ''} ${ing.ingredient?.unit_default || ing.unit || ''}`.trim(),
                        inInventory
                    };
                });

                setRecipe({
                    id: r.id.toString(),
                    name: r.title,
                    tag: "RECETA LOCAL",
                    portions: 2,
                    timeMinutes: 30,
                    inventoryCount: mappedIngredients.filter((i: any) => i.inInventory).length,
                    totalCount: mappedIngredients.length,
                    imageUrl: r.image_url,
                    ingredients: mappedIngredients
                });
            }
        };
        fetchRecipe();
    }, [recipeId]);

    const handleBuyIngredients = () => {
        const saved = localStorage.getItem("biteWise_shoppingLists");
        let lists = [];
        if (saved) {
            lists = JSON.parse(saved);
        }

        const missingIngredients = recipe.ingredients.filter((i: any) => !i.inInventory);
        const toBuy = missingIngredients.length > 0 ? missingIngredients : recipe.ingredients;

        const items = toBuy.map((ing: any, idx: number) => ({
            id: `ing-${Date.now()}-${idx}`,
            name: ing.name,
            quantity: ing.amount || '1',
            checked: false
        }));

        const listId = Date.now().toString();
        const newList = {
            id: listId,
            name: `Faltantes: ${recipe.name}`,
            status: "incomplete",
            createdLabel: "Justo ahora",
            progress: 0,
            total: items.length
        };
        lists.push(newList);
        localStorage.setItem("biteWise_shoppingLists", JSON.stringify(lists));

        // Save items to the list's storage key
        localStorage.setItem(`biteWise_list_items_${listId}`, JSON.stringify(items));
        // Also save as pending items (backup)
        localStorage.setItem('biteWise_pendingItems', JSON.stringify(items));

        alert(`✅ Se creó la lista "${newList.name}" con ${items.length} ingredientes.`);
        router.push(`/shopping-list-detail?id=${listId}`);
    };

    return (
        <div className="flex h-screen overflow-hidden bg-white dark:bg-background-dark">
            <Sidebar activeTab="recetas" />

            <div className="flex-1 flex flex-col overflow-y-auto">
                <Header title="Detalles de la Receta" />

                {!recipe ? (
                    <div className="p-8 text-center text-gray-500">Cargando receta...</div>
                ) : (
                    <>
                        {/* Breadcrumb header */}
                        <header className="bg-white dark:bg-background-dark border-b border-gray-200 dark:border-white/10 px-6 py-3 flex items-center gap-2 shrink-0">
                            <button onClick={() => router.back()} className="text-gray-400 dark:text-gray-500 hover:text-gray-700 dark:hover:text-gray-300 transition-colors">
                                <ArrowLeft size={16} />
                            </button>
                            <span className="text-xs text-gray-400 dark:text-gray-400">Recetas</span>
                            <span className="text-xs text-gray-300 dark:text-gray-500">/</span>
                            <span className="text-xs text-gray-600 dark:text-gray-200 font-medium truncate">{recipe.name}</span>
                        </header>

                        <main className="flex-1 overflow-y-auto">
                            {/* Hero image area */}
                            <div className="relative h-48 sm:h-56 bg-gray-200 dark:bg-white/5 overflow-hidden">
                                {/* Image placeholder or Real image */}
                                <div className="absolute inset-0 flex items-center justify-center bg-gray-200 dark:bg-zinc-800 border-b border-white/10">
                                    {recipe.imageUrl ? (
                                        <img
                                            src={recipe.imageUrl}
                                            alt={recipe.name}
                                            className="w-full h-full object-cover"
                                        />
                                    ) : (
                                        <span className="text-gray-400 dark:text-white/20 text-5xl">🍽️</span>
                                    )}
                                </div>

                                {/* Dark overlay for text legibility */}
                                <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-black/20 to-transparent" />

                                {/* Tag */}
                                <div className="absolute top-4 left-4">
                                    <span className="bg-emerald-500 text-white text-[10px] font-bold px-2.5 py-1 rounded-md uppercase tracking-wide">
                                        {recipe.tag}
                                    </span>
                                </div>

                                {/* Title + meta */}
                                <div className="absolute bottom-4 left-4 right-4">
                                    <h1 className="text-white text-2xl font-bold drop-shadow-md leading-tight">
                                        {recipe.name}
                                    </h1>
                                    <div className="flex items-center gap-4 mt-2">
                                        <span className="flex items-center gap-1.5 text-white/80 text-xs">
                                            <Users size={12} />
                                            {recipe.portions} porciones
                                        </span>
                                    </div>
                                </div>
                            </div>

                            {/* Body */}
                            <div className="px-6 py-6 max-w-2xl mx-auto w-full">
                                {/* Ingredients section */}
                                <div className="bg-white dark:bg-background-dark border border-gray-200 dark:border-white/10 rounded-xl overflow-hidden mb-6">
                                    <div className="flex items-center justify-between px-5 py-3.5 border-b border-gray-100 dark:border-white/10 bg-gray-50/50 dark:bg-white/5">
                                        <h2 className="text-sm font-bold text-gray-800 dark:text-gray-200">
                                            Ingredientes (en inventario)
                                        </h2>
                                        <span className="text-xs text-gray-500 dark:text-gray-400">
                                            {recipe.inventoryCount}/{recipe.totalCount} ITEMS
                                        </span>
                                    </div>
                                    <div className="px-5 py-1">
                                        {recipe.ingredients.length === 0 ? (
                                            <p className="text-sm text-gray-500 dark:text-gray-400 py-4 text-center">
                                                Cargando ingredientes...
                                            </p>
                                        ) : (
                                            recipe.ingredients.map((ingredient: any) => (
                                                <IngredientRow key={ingredient.id} ingredient={ingredient} />
                                            ))
                                        )}
                                    </div>
                                </div>
                            </div>
                        </main>

                        {/* Bottom action bar */}
                        <div className="bg-white dark:bg-background-dark border-t border-gray-200 dark:border-white/10 px-6 py-4 flex flex-col sm:flex-row items-center justify-between gap-3 shrink-0">
                            <div className="flex items-center gap-1.5 text-xs text-gray-600 dark:text-gray-400 font-medium">
                                <Clock size={13} className="text-gray-500 dark:text-gray-400" />
                                Tiempo aproximado: {recipe.timeMinutes} min
                            </div>

                            <div className="flex flex-col sm:flex-row items-center gap-3 w-full sm:w-auto">
                                <button
                                    onClick={handleBuyIngredients}
                                    className="flex items-center justify-center gap-2 bg-emerald-500/10 hover:bg-emerald-500/20 text-emerald-600 dark:text-emerald-400 text-sm font-bold px-5 py-2.5 rounded-xl transition-colors w-full sm:w-auto"
                                >
                                    <ShoppingBag size={15} />
                                    Comprar Ingredientes
                                </button>
                                <button
                                    onClick={() => router.push(`/kitchen?recipeId=${recipe.id}`)}
                                    className="flex items-center justify-center gap-2 bg-emerald-500 hover:bg-emerald-600 text-white text-sm font-bold px-5 py-2.5 rounded-xl transition-colors shadow-sm shadow-emerald-200 dark:shadow-none w-full sm:w-auto"
                                >
                                    <PlayCircle size={15} />
                                    ¡Empezar a cocinar!
                                </button>
                            </div>
                        </div>
                    </>
                )}
            </div>
        </div>
    );
}

"use client";

import React, { useState, useRef } from "react";
import { Search, CheckCircle2, Trash2 } from "lucide-react";
import { Sidebar } from "@/features/dashboard/components/Sidebar";
import { Header } from "@/features/dashboard/components/Header";
import ShoppingItemRow from "@/features/shopping-list-detail/components/ShoppingItemRow";
import { type ShoppingItem } from "@/features/shopping-list-detail/listaDetalleData";
import { useSearchParams } from "next/navigation";

export default function ListaDetalleView() {
    const searchParams = useSearchParams();
    const urlListId = searchParams.get('id');

    const [items, setItems] = useState<ShoppingItem[]>([]);
    const [newItemName, setNewItemName] = useState("");
    const [listName, setListName] = useState("Mi Lista de Compras");
    const [activeListId, setActiveListId] = useState<string>("default");
    const hasInitialized = useRef(false);

    // Initialize list and merge any pending items sent from Recipe Detail
    React.useEffect(() => {
        let activeId: string = urlListId ?? "";

        // Find best active ID
        const savedLists = localStorage.getItem('biteWise_shoppingLists');
        let parsedLists: any[] = [];
        if (savedLists) {
            try { parsedLists = JSON.parse(savedLists); } catch (e) { }
        }

        if (!activeId) {
            if (parsedLists.length > 0) {
                activeId = parsedLists[0].id;
                setListName(parsedLists[0].name);
            } else {
                activeId = "default";
            }
        } else {
            const found = parsedLists.find((l: any) => l.id === activeId);
            if (found) {
                setListName(found.name);
            }
        }

        setActiveListId(activeId);

        let currentItems: ShoppingItem[] = [];

        // 1. Try to load existing active list items
        const storageKey = `biteWise_list_items_${activeId}`;
        const savedList = localStorage.getItem(storageKey);

        if (savedList) {
            try {
                const parsed = JSON.parse(savedList);
                if (Array.isArray(parsed)) {
                    currentItems = parsed;
                }
            } catch (e) {
                console.error("Error parsing saved list", e);
            }
        }

        // 2. Try to load pending items to append
        const pending = localStorage.getItem('biteWise_pendingItems');
        if (pending) {
            try {
                const parsed = JSON.parse(pending) as ShoppingItem[];
                if (Array.isArray(parsed) && parsed.length > 0) {
                    const existingNames = new Set(currentItems.map(i => i.name.toLowerCase()));
                    const newItems = parsed.filter(i => !existingNames.has(i.name.toLowerCase()));

                    if (newItems.length > 0) {
                        currentItems = [...newItems, ...currentItems];
                    }
                }
            } catch (e) {
                console.error("Error parsing pending items", e);
            }
            localStorage.removeItem('biteWise_pendingItems');
        }

        // Save items immediately if we loaded any
        localStorage.setItem(storageKey, JSON.stringify(currentItems));

        setItems(currentItems);

        // Mark as initialized AFTER React commits the state
        setTimeout(() => { hasInitialized.current = true; }, 0);
    }, [urlListId]);

    // Save changes to localStorage whenever items change — only AFTER initialization
    React.useEffect(() => {
        if (hasInitialized.current) {
            localStorage.setItem(`biteWise_list_items_${activeListId}`, JSON.stringify(items));
        }
    }, [items, activeListId]);

    const checkedCount = items.filter((i) => i.checked).length;
    const allChecked = checkedCount === items.length && items.length > 0;

    const handleToggle = (id: string) => {
        setItems((prev) =>
            prev.map((item) => (item.id === id ? { ...item, checked: !item.checked } : item))
        );
    };

    const handleDelete = (id: string) => {
        setItems((prev) => prev.filter((item) => item.id !== id));
    };

    const handleAddItem = () => {
        const trimmed = newItemName.trim();
        if (!trimmed) return;
        const newItem: ShoppingItem = {
            id: `item-${Date.now()}`,
            name: trimmed,
            quantity: "",
            checked: false,
        };
        setItems((prev) => [...prev, newItem]);
        setNewItemName("");
    };

    const handleMarkAll = () => {
        setItems((prev) => prev.map((item) => ({ ...item, checked: true })));
    };

    const handleComplete = async () => {
        // Mark all checked first (visual feedback)
        const allCheckedItems = items.map(item => ({ ...item, checked: true }));
        setItems(allCheckedItems);

        const token = localStorage.getItem('token');
        if (!token) {
            alert("Necesitas iniciar sesión para transferir al inventario.");
            return;
        }

        // Use services instead of manual fetch
        const { catalogService } = await import("@/services/catalog.service");
        const { inventoryService } = await import("@/services/inventory.service");

        let successCount = 0;
        let errorCount = 0;

        for (const item of allCheckedItems) {
            try {
                // Parse quantity and check for units
                const qtyStr = item.quantity.toLowerCase();
                const numericMatch = qtyStr.match(/(\d+(\.\d+)?)/);
                const numericQty = numericMatch ? parseFloat(numericMatch[0]) : 1;

                // If it doesn't mention 'g', 'ml', 'kg', 'l', assume it's 'units'
                const isMass = qtyStr.includes('g') || qtyStr.includes('ml') || qtyStr.includes('kg') || qtyStr.includes('l');
                const defaultWPU = isMass ? 1 : 250; // Use 250g as a better guess for a "unit" of something if not specified

                // 1. Find or create ingredient in catalog
                const ingredientsRes = await catalogService.getIngredients(token);
                let ingredient_id: number | null = null;
                let weight_per_unit = defaultWPU;

                if (ingredientsRes.ok && Array.isArray(ingredientsRes.data)) {
                    const found = ingredientsRes.data.find(
                        (ing: any) => ing.name?.toLowerCase().trim() === item.name.toLowerCase().trim()
                    );
                    if (found) {
                        ingredient_id = found.id;
                        weight_per_unit = Number(found.weight_per_unit) || 1;
                    }
                }

                // 2. If not found, create it with guessed weight
                if (!ingredient_id) {
                    const createRes = await catalogService.createIngredient({
                        name: item.name,
                        category: 'Importado',
                        purchase_price: 0.05,
                        purchase_quantity: 1,
                        unit_default: isMass && qtyStr.includes('ml') ? 'ml' : 'g',
                        weight_per_unit: defaultWPU
                    }, token);

                    if (createRes.ok && createRes.data?.ingredient) {
                        ingredient_id = createRes.data.ingredient.id;
                    }
                }

                if (!ingredient_id) {
                    errorCount++;
                    continue;
                }

                // 3. Add to user inventory with correctly parsed quantity
                // If the user bought 500g, and wpu is 1, we add 500 units.
                // If the user bought 2 pieces, and wpu is 250, we add 2 units.
                const invRes = await inventoryService.createInventoryItem({
                    ingredient_id,
                    quantity: numericQty
                }, token);

                if (invRes.ok) {
                    successCount++;
                } else {
                    console.error(`Failed to add ${item.name} to inventory:`, invRes.error);
                    errorCount++;
                }
            } catch (e) {
                console.error(`Error processing ${item.name}:`, e);
                errorCount++;
            }
        }

        if (successCount > 0) {
            alert(`✅ ${successCount} ingrediente(s) añadidos a tu inventario.${errorCount > 0 ? ` (${errorCount} no se pudieron procesar.)` : ''}`);
        } else if (errorCount > 0) {
            alert(`❌ No se pudieron añadir los ingredientes al inventario. Por favor, revisa la consola para más detalles.`);
        }
    };

    return (
        <div className="flex h-screen overflow-hidden bg-white dark:bg-background-dark">
            <Sidebar activeTab="lista" />

            <div className="flex-1 flex flex-col overflow-y-auto">
                <Header title="Detalles de Lista" />

                <main className="flex-1 flex items-start justify-center pt-12 px-4 sm:px-8 pb-8">
                    <div className="w-full max-w-sm sm:max-w-md lg:max-w-lg">
                        {/* List card */}
                        <div className="bg-white dark:bg-background-dark border border-gray-200 dark:border-white/10 rounded-2xl shadow-sm overflow-hidden">
                            {/* Card header */}
                            <div className="flex items-center justify-between px-4 sm:px-6 py-4 border-b border-gray-100 dark:border-white/10">
                                <h2 className="text-sm font-bold text-gray-900 dark:text-white uppercase tracking-wide">
                                    {listName}
                                </h2>
                                <span className="text-[11px] text-emerald-500 font-semibold">
                                    {checkedCount}/{items.length} productos
                                </span>
                            </div>

                            {/* Items */}
                            <div className="px-4 sm:px-6 py-2">
                                {items.map((item) => (
                                    <ShoppingItemRow
                                        key={item.id}
                                        item={item}
                                        onToggle={handleToggle}
                                        onDelete={handleDelete}
                                    />
                                ))}
                            </div>

                            {/* Add item input */}
                            <div className="px-4 sm:px-6 pb-4 pt-2">
                                <div className="flex items-center gap-2 border border-gray-200 dark:border-white/10 rounded-lg px-3 py-2 focus-within:ring-2 focus-within:ring-emerald-500 focus-within:border-transparent transition-all bg-white dark:bg-white/5">
                                    <Search size={13} className="text-gray-400 shrink-0" />
                                    <input
                                        type="text"
                                        placeholder="+ Agregar producto"
                                        value={newItemName}
                                        onChange={(e) => setNewItemName(e.target.value)}
                                        onKeyDown={(e) => e.key === "Enter" && handleAddItem()}
                                        className="flex-1 text-sm text-gray-700 dark:text-gray-200 placeholder-gray-400 outline-none bg-transparent"
                                    />
                                </div>
                            </div>

                            {/* CTA Button */}
                            <div className="px-4 sm:px-6 pb-4">
                                <button
                                    onClick={allChecked ? undefined : handleComplete}
                                    disabled={allChecked}
                                    className={`w-full py-3 rounded-xl text-sm sm:text-base font-bold flex items-center justify-center gap-2 transition-all duration-200 ${allChecked
                                        ? "bg-emerald-50 dark:bg-emerald-500/10 text-emerald-500 cursor-default"
                                        : "bg-emerald-500 hover:bg-emerald-600 text-white shadow-sm"
                                        }`}
                                >
                                    <CheckCircle2 size={16} />
                                    {allChecked ? "¡Todo completado!" : "TODO COMPRADO"}
                                </button>
                                <p className="text-[10px] text-gray-400 dark:text-gray-500 text-center mt-2">
                                    LOS ARTÍCULOS MARCADOS SE TRANSFERIRÁN A TU INVENTARIO
                                </p>
                            </div>
                        </div>
                    </div>
                </main>

                {/* Footer */}
                <footer className="py-4 text-center">
                    <p className="text-xs text-gray-400">
                        © 2024 <span className="font-semibold">BiteWise</span>. Come mejor, desperdicia menos.
                    </p>
                </footer>
            </div>
        </div>
    );
}

